def _execute_server_warmup(server_args: ServerArgs):
    headers = {}
    url = server_args.url()
    if server_args.api_key:
        headers["Authorization"] = f"Bearer {server_args.api_key}"

    ssl_verify = server_args.ssl_verify()

    # Wait until the server is launched
    success = False
    for _ in range(120):
        time.sleep(1)
        try:
            res = requests.get(
                url + "/model_info", timeout=5, headers=headers, verify=ssl_verify
            )
            assert res.status_code == 200, f"{res=}, {res.text=}"
            success = True
            break
        except (AssertionError, requests.exceptions.RequestException):
            last_traceback = get_exception_traceback()
            pass

    if not success:
        logger.error(f"Initialization failed. warmup error: {last_traceback}")
        kill_process_tree(os.getpid())
        return success

    model_info = res.json()

    # Construct a warmup request (MLX: text warmup for VLM-advertising models; TODO: enable image warmup).
    # A language-only worker may advertise VLM capability for encoder
    # disaggregation, but its local warmup must stay on the text path.
    is_vlm = (
        bool(model_info.get("has_image_understanding", False))
        and not server_args.language_only
        and not is_mps()
    )
    if model_info["is_generation"]:
        if is_vlm and not server_args.skip_tokenizer_init:
            request_name = "/v1/chat/completions"
        else:
            request_name = "/generate"
    else:
        request_name = "/encode"
    max_new_tokens = 8 if model_info["is_generation"] else 1
    json_data = {
        "sampling_params": {
            "temperature": 0,
            "max_new_tokens": max_new_tokens,
        },
    }
    if server_args.skip_tokenizer_init:
        json_data["input_ids"] = [[10, 11, 12] for _ in range(server_args.dp_size)]
        # TODO Workaround the bug that embedding errors for list of size 1
        if server_args.dp_size == 1:
            json_data["input_ids"] = json_data["input_ids"][0]
    elif (
        is_vlm
        and server_args.disaggregation_mode == "null"
        and model_info["is_generation"]
    ):
        # TODO: ChatCompletionRequest does not have bootstrap info required by disaggregation mode, disable image-warmup for now
        # Only use chat completions format for generation models, not embedding models
        json_data = {
            "model": _global_state.tokenizer_manager.served_model_name,
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "image_url",
                            "image_url": {
                                "url": "data:image/png;base64,"
                                f"{_get_vlm_warmup_image_base64(model_info)}"
                            },
                        },
                        {
                            "type": "text",
                            "text": "Describe the image.",
                        },
                    ],
                }
            ],
            "max_tokens": max_new_tokens,
            "stream": False,
            "temperature": 0.0,
        }
    else:
        json_data["text"] = ["The capital city of France is"] * server_args.dp_size
        # TODO Workaround the bug that embedding errors for list of size 1
        if server_args.dp_size == 1:
            json_data["text"] = json_data["text"][0]

    # Config debug dumping
    if server_args.debug_tensor_dump_input_file:
        json_data.pop("text", None)
        json_data["input_ids"] = np.load(
            server_args.debug_tensor_dump_input_file
        ).tolist()
        json_data["sampling_params"]["max_new_tokens"] = 0

    # Send a warmup request
    warmup_timeout = envs.SGLANG_WARMUP_TIMEOUT.get()
    try:
        if server_args.disaggregation_mode == "null":
            res = requests.post(
                url + request_name,
                json=json_data,
                headers=headers,
                timeout=warmup_timeout if warmup_timeout > 0 else 600,
                verify=ssl_verify,
            )
            assert res.status_code == 200, f"{res.text}"
            _global_state.tokenizer_manager.server_status = ServerStatus.Up

        else:
            logger.info(f"Start of pd disaggregation warmup ...")
            status_codes = asyncio.run(
                _send_disaggregation_warmup_requests(
                    server_args=server_args,
                    url=url,
                    headers=headers,
                    ssl_verify=ssl_verify,
                    timeout=warmup_timeout if warmup_timeout > 0 else 1800,
                )
            )
            failed_status_codes = [code for code in status_codes if code != 200]
            if not failed_status_codes:
                logger.info(
                    "Disaggregation warmup requests completed for all %s DP ranks",
                    server_args.dp_size,
                )
                logger.info("End of disaggregation warmup")
                _global_state.tokenizer_manager.server_status = ServerStatus.Up
            else:
                logger.info(
                    "Disaggregation warmup failed (mode=%s), status codes: %s",
                    server_args.disaggregation_mode,
                    failed_status_codes,
                )
                _global_state.tokenizer_manager.server_status = ServerStatus.UnHealthy

    except Exception:
        last_traceback = get_exception_traceback()
        logger.error(f"Initialization failed. warmup error: {last_traceback}")
        kill_process_tree(os.getpid())
        return False

    return success

def from_cli_args(cls, args: argparse.Namespace):
    # Some dataclass fields (e.g. stat_loggers) intentionally have no CLI
    # surface and won't appear on the argparse Namespace. Skip them so the
    # dataclass default applies.
    attrs = [
        attr.name for attr in dataclasses.fields(cls) if hasattr(args, attr.name)
    ]
    return cls(**{attr: getattr(args, attr) for attr in attrs})

def get_tokenizer_worker_class(self):
    from sglang.srt.managers.multi_tokenizer_mixin import TokenizerWorker

    return TokenizerWorker

def url(self, port: Optional[int] = None):
    scheme = "https" if self.ssl_certfile else "http"
    # When binding to all interfaces, use loopback for internal requests.
    host = self.host
    if not host or host == "0.0.0.0":
        host = "127.0.0.1"
    elif host == "::":
        host = "::1"
    return NetworkAddress(host, port if port is not None else self.port).to_url(
        scheme
    )

@property
def engine_info_bootstrap_url(self):
    return self.url(port=self.engine_info_bootstrap_port)

@property
def is_ep_joiner(self) -> bool:
    """True for processes launched as elastic-EP joiners."""
    return self.ep_join_mode in ("scale", "recover")

@property
def is_ep_scale_joiner(self) -> bool:
    return self.ep_join_mode == "scale"

def ssl_verify(self):
    """Return the value for the requests library's verify= parameter.

    When SSL is configured:
      - If a CA certificate file is provided, return its path so requests
        validates the server certificate against that CA.
      - Otherwise, return False to disable certificate verification
        (suitable for self-signed certificates in development/testing).
        A warning is logged once when this happens.
    When SSL is not configured, return True to use the system's default
    CA bundle.
    """
    if self.ssl_ca_certs:
        return self.ssl_ca_certs
    if self.ssl_certfile:
        if not getattr(self, "_ssl_verify_warned", False):
            logger.warning(
                "SSL is enabled but --ssl-ca-certs was not provided. "
                "Certificate verification is DISABLED for internal "
                "health checks. For production deployments, provide "
                "--ssl-ca-certs or use CA-signed certificates."
            )
            self._ssl_verify_warned = True
        return False
    return True

def get_model_config(self):
    # Lazy init to avoid circular import
    from sglang.srt.configs.model_config import ModelConfig

    if hasattr(self, "model_config"):
        return self.model_config
    self.model_config = ModelConfig.from_server_args(self)
    return self.model_config

